/**
 * 对象数组、普通数组冒泡排序
 * @param obj
 * @param arrKey
 * @param orderby
 * @returns
 * 对象数组使用  bubbleSort(arr,key,orderby)
 * 普通数组使用  bubbleSort(arr) bubbleSort(arr,'',orderby)
 */
declare function bubbleSort(obj: (object | string | number)[], arrKey: string, orderby?: 'asc' | 'desc'): any[];
export default bubbleSort;
